const D=window.DEMO_DATA, list=document.querySelector('#claimList'), sources=document.querySelector('#sourceList'), detail=document.querySelector('#detail'), overview=document.querySelector('#overview');let filter='All';
function renderClaims(){const q=document.querySelector('#search').value.toLowerCase();list.innerHTML=D.claims.filter(c=>(filter==='All'||c.verdict===filter)&&(!q||(`${c.title} ${c.detail}`).toLowerCase().includes(q))).map(c=>`<article class="claim" tabindex="0" data-id="${c.id}"><div><h3>${c.title}</h3><p>${c.support} supportive · ${c.oppose} contradictory · ${c.sources} sources</p></div><div class="claim-side"><div class="score">${c.score}</div><div class="verdict">${c.verdict} →</div></div></article>`).join('')||'<p class="muted">No matching demo evidence.</p>';document.querySelectorAll('.claim').forEach(e=>{e.onclick=()=>showDetail(e.dataset.id);e.onkeydown=x=>{if(x.key==='Enter')showDetail(e.dataset.id)}})}
function renderSources(){sources.innerHTML=D.sources.map(s=>`<article class="source"><span class="source-type">${s.type}</span><h3>${s.title}</h3><small>${s.journal}<br>${s.year} · ${s.quality} quality</small></article>`).join('')}
function showDetail(id){const c=D.claims.find(x=>x.id===id);overview.classList.add('hidden');detail.classList.remove('hidden');detail.innerHTML=`<article class="card detail-card"><a href="#overview" class="small-link" id="back">← Back to overview</a><p class="eyebrow" style="margin-top:32px">Claim detail · ${c.id}</p><h2>${c.title}</h2><p class="lede">${c.detail}</p><div class="summary-grid"><div><p class="eyebrow">Evidence signal</p><div class="score">${c.score} <span class="muted">/ 100</span></div></div><div><p class="eyebrow">Balance</p><p>${c.support} supportive · ${c.oppose} contradictory</p></div></div><h3>Provenance</h3><p class="muted">${c.sources} illustrative sources linked · score is a demo visualization, not a medical conclusion.</p></article>`;document.querySelector('#back').onclick=()=>{detail.classList.add('hidden');overview.classList.remove('hidden')}}
document.querySelectorAll('.filter').forEach(b=>b.onclick=()=>{filter=b.dataset.filter;document.querySelectorAll('.filter').forEach(x=>x.classList.toggle('active',x===b));renderClaims()});document.querySelector('#search').oninput=renderClaims;document.querySelector('#shareBtn').onclick=()=>{const t=document.querySelector('#toast');t.textContent='Demo view link copied';t.classList.add('show');setTimeout(()=>t.classList.remove('show'),1800)};document.addEventListener('keydown',e=>{if(e.key==='/'&&document.activeElement.tagName!=='INPUT'){e.preventDefault();document.querySelector('#search').focus()}});renderClaims();renderSources();
